  import sailpoint.object.Identity;
  import sailpoint.object.Custom;
  import java.util.List;
  import org.apache.log4j.Logger;
  import java.util.Date;
  import java.text.SimpleDateFormat;


  boolean conversionTrigger = false;
  boolean rehireTrigger = false;
  String newRehireType=null;
  String previousAction=null;
  String newAction=null;

   Logger logger = Logger.getLogger("com.CustomLogs");
  logger.debug("Inside Rehire-Conversion trigger rule - START");
  try{
    if(previousIdentity!= null && newIdentity!= null){
      logger.debug("Rehire/Conversion trigger rule::identityName= "+newIdentity.getName());

      boolean isInactiveUser=newIdentity.isInactive();

      previousStatus = previousIdentity.getStringAttribute("status");
      newAction = newIdentity.getStringAttribute("action");    
      previousAction = previousIdentity.getStringAttribute("action"); 
      
      String newType = newIdentity.getStringAttribute("type");    
      String previousType= previousIdentity.getStringAttribute("type"); 

      if(previousType!=null &&  newType!=null && !(previousType.equalsIgnoreCase(newType)) && (newType.equalsIgnoreCase("employee") || newType.equalsIgnoreCase("physician") || newType.equalsIgnoreCase("contractor")) ){
       
        if( newType.equalsIgnoreCase("contractor") && (newAction!=null && newAction.equalsIgnoreCase("ADD") ) ){
       
          conversionTrigger=true;
          return conversionTrigger;

        }
        if( (newType.equalsIgnoreCase("employee") || newType.equalsIgnoreCase("physician")) && (newAction!=null && (newAction.equalsIgnoreCase("REH") || newAction.equalsIgnoreCase("HIR")))){
          
          conversionTrigger=true;
          return conversionTrigger;

        }

      }
    }
    return "false";

  }catch(Exception e){
    log.error("Exception= ");
    e.printStackTrace();
    throw e;
  }
